const menuToggle=document.querySelector('.menu-toggle');const siteNav=document.querySelector('.site-nav');if(menuToggle && siteNav){menuToggle.addEventListener('click',()=>{siteNav.classList.toggle('open');});siteNav.querySelectorAll('a').forEach((link)=>{link.addEventListener('click',()=>{siteNav.classList.remove('open');});});}const adminParam=new URLSearchParams(window.location.search).get('admin');const adminHash=window.location.hash==='#admin';if(adminParam==='1' || adminHash){document.body.classList.add('admin-visible');}const configStorageKey='calcagnotoConfig';const configFields=[ 'whatsapp','endereco','email','oab','cnpj','nome_advogado','linkedin','instagram','youtube' ];const readText=(selector)=>{const element=document.querySelector(selector);return element ? element.textContent.trim():'';};const getInitialConfig=()=>{const config={endereco:readText('[data-field="endereco"]'),email:readText('[data-field="email"]'),oab:readText('[data-field="oab"]'),cnpj:readText('[data-field="cnpj"]'),nome_advogado:readText('[data-field="nome_advogado"]')};const whatsappLink=document.querySelector('[data-whatsapp-link]');if(whatsappLink){const href=whatsappLink.getAttribute('href')|| '';const match=href.match(/wa\.me\/([^?]+)/);config.whatsapp=match ? match[1]:'';}const emailLink=document.querySelector('[data-email-link]');if(emailLink){const emailHref=emailLink.getAttribute('href')|| '';const match=emailHref.match(/mailto:(.*)/);if(match && match[1]){config.email=match[1];}}['linkedin','instagram','youtube'].forEach((field)=>{const element=document.querySelector(`[data-social-link="${field}"]`);if(element){config[field]=element.getAttribute('href')|| '';}});return config;};const normalizeWhatsapp=(value)=>value.replace(/\D/g,'');const applyConfig=(config)=>{const safeConfig={...config};safeConfig.whatsapp=normalizeWhatsapp(config.whatsapp || '');['endereco','email','oab','cnpj','nome_advogado'].forEach((field)=>{const elements=document.querySelectorAll(`[data-field="${field}"]`);elements.forEach((element)=>{if(safeConfig[field]){element.textContent=safeConfig[field];}});});if(safeConfig.email){document.querySelectorAll('[data-email-link]').forEach((element)=>{element.setAttribute('href',`mailto:${safeConfig.email}`);});}if(safeConfig.whatsapp){document.querySelectorAll('[data-whatsapp-link]').forEach((element)=>{element.setAttribute('href',`https://wa.me/${safeConfig.whatsapp}`);});document.querySelectorAll('[data-field="whatsapp_text"]').forEach((element)=>{element.textContent=safeConfig.whatsapp;});}['linkedin','instagram','youtube'].forEach((field)=>{if(safeConfig[field]){document.querySelectorAll(`[data-social-link="${field}"]`).forEach((element)=>{element.setAttribute('href',safeConfig[field]);});}});};const initialConfig=getInitialConfig();let storedConfig={};try{const raw=localStorage.getItem(configStorageKey);if(raw)storedConfig=JSON.parse(raw);}catch(error){storedConfig={};}const activeConfig={...initialConfig,...storedConfig};applyConfig(activeConfig);const adminForm=document.querySelector('[data-admin-form]');const adminReset=document.querySelector('[data-admin-reset]');const fillAdminForm=(config)=>{if(!adminForm)return;configFields.forEach((field)=>{const input=adminForm.elements[field];if(input){input.value=config[field] || '';}});};fillAdminForm(activeConfig);if(adminForm){adminForm.addEventListener('submit',(event)=>{event.preventDefault();const formData=new FormData(adminForm);const nextConfig={...initialConfig};configFields.forEach((field)=>{const value=(formData.get(field)|| '').toString().trim();if(value){nextConfig[field]=value;}});if(nextConfig.whatsapp){nextConfig.whatsapp=normalizeWhatsapp(nextConfig.whatsapp);}localStorage.setItem(configStorageKey,JSON.stringify(nextConfig));applyConfig(nextConfig);fillAdminForm(nextConfig);});}if(adminReset){adminReset.addEventListener('click',()=>{localStorage.removeItem(configStorageKey);applyConfig(initialConfig);fillAdminForm(initialConfig);});}const faqItems=document.querySelectorAll('.faq-item');faqItems.forEach((item)=>{const button=item.querySelector('.faq-question');const answer=item.querySelector('.faq-answer');if(!button || !answer)return;button.addEventListener('click',()=>{const isOpen=item.classList.contains('open');item.classList.toggle('open');button.setAttribute('aria-expanded',String(!isOpen));if(!isOpen){answer.style.maxHeight=`${answer.scrollHeight}px`;}else{answer.style.maxHeight='0px';}});});window.addEventListener('resize',()=>{faqItems.forEach((item)=>{const answer=item.querySelector('.faq-answer');if(item.classList.contains('open')&& answer){answer.style.maxHeight=`${answer.scrollHeight}px`;}});});const contactForm=document.querySelector('.contact-form');const formFeedback=document.querySelector('[data-form-feedback]');if(contactForm){const requiredFields=contactForm.querySelectorAll('[required]');contactForm.addEventListener('submit',(event)=>{let isValid=true;requiredFields.forEach((field)=>{if(!field.checkValidity()){isValid=false;field.classList.add('is-invalid');field.setAttribute('aria-invalid','true');}});if(!isValid){event.preventDefault();if(formFeedback){formFeedback.textContent='Por favor,preencha os campos obrigatórios para agendar a análise.';}}else if(formFeedback){formFeedback.textContent='';}});requiredFields.forEach((field)=>{field.addEventListener('input',()=>{field.classList.remove('is-invalid');field.removeAttribute('aria-invalid');if(formFeedback)formFeedback.textContent='';});});}